```javascript
import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const nowDate = new Date(now);

    const reqRow = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];
    const acctRow = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];

    const { tier } = acctRow;
    const { request_id, account_id, invoices_json, shipments_json, regulatory_json, support_json, prior_period_units, current_period_units } = reqRow;

    const invoices = invoices_json || [];
    const shipments = shipments_json || [];
    const regulatoryFlags = regulatory_json || [];
    const supportCases = support_json || [];
    const prior = Number(prior_period_units);
    const current = Number(current_period_units);

    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open")) {
      signals.push("Regulatory hold");
    }
    if (invoices.some(inv => inv.status !== "paid" && new Date(inv.dueDate) < nowDate && inv.amountCents >= 2500000)) {
      signals.push("Overdue invoice");
    }
    if (shipments.some(s => !s.deliveredDate && new Date(s.slaDate) < nowDate)) {
      signals.push("Delayed shipment");
    }
    if (supportCases.some(c => c.status === "open" && (c.severity === "high" || c.severity === "critical"))) {
      signals.push("Escalated support");
    }
    if (current <= prior * 0.7) {
      signals.push("Usage decline");
    }

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(tier) && signals.length > 0;

    let status, nextStep, riskSummary, owners;

    if (qualifies) {
      status = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
      riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

      const signalToOwner = {
        "Regulatory hold": "Legal",
        "Overdue invoice": "Finance",
        "Delayed shipment": "Customer Success",
        "Escalated support": "Support",
        "Usage decline": "Customer Success",
      };
      const ownerSet = new Set(signals.map(s => signalToOwner[s]).filter(Boolean));
      const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
      owners = ownerOrder.filter(o => ownerSet.has(o));
      nextStep = `${owners[0]} recovery review by 16:00`;
    } else {
      status = "Monitoring — no escalation required.";
      nextStep = "Continue standard monitoring.";
      riskSummary = signals.length > 0 ? `${signals.length} signals: ${signals.join(", ")}` : "0 signals";
      owners = [];
    }

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [account_id]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [account_id]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [request_id, account_id, reqRow.title, status, nextStep, riskSummary]
    );

    const dueAt = new Date(nowDate.getTime() + 24 * 60 * 60 * 1000);
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [request_id, account_id, owner, `${owner} recovery review`, dueAt.toISOString(), "open"]
      );
    }

    const messageBody = qualifies
      ? `Your account has been flagged for escalation due to ${signals.length} active risk signal(s): ${signals.join(", ")}. Our dedicated recovery teams have been engaged to address these issues. A recovery owner has been assigned to your account and will be in touch shortly with next steps and a resolution timeline. We remain committed to your success and appreciate your continued partnership.`
      : `Your account is currently under standard monitoring and no escalation is required at this time. We will continue to monitor your account status and will notify you promptly if any issues arise. Thank you for your continued partnership.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [request_id, account_id, messageBody]
    );

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [request_id, account_id, `Rescue workflow initiated: ${status}`, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
